+const std = @import("std");
+const model_hash = @import("model_hash.zig");
+
+const c = @cImport({
+    @cInclude("stdlib.h");
+});
+
+/// Check if Metal compiler toolchain (xcrun) is available
+pub fn checkMetalAvailable() bool {
+    // Try to find xcrun metal compiler
+    const result = std.process.Child.run(.{
+        .allocator = std.heap.page_allocator,
+        .argv = &[_][]const u8{ "xcrun", "--find", "metal" },
+    }) catch return false;
+
+    defer std.heap.page_allocator.free(result.stdout);
+    defer std.heap.page_allocator.free(result.stderr);
+
+    return result.term.Exited == 0;
+}
+
+/// Compile Metal shaders to .metallib and cache them
+/// Returns the path to the cached .metallib file
+pub fn compileMetalShaders(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+) ![]u8 {
+    std.debug.print("Pre-compiling Metal shaders...\n", .{});
+
+    // Get shader cache path
+    const shader_path = try model_hash.getShaderPath(allocator, model_path);
+    errdefer allocator.free(shader_path);
+
+    // Check if already cached
+    std.fs.cwd().access(shader_path, .{}) catch {
+        // Not cached, need to compile
+        try compileShaderLibrary(allocator, shader_path);
+    };
+
+    return shader_path;
+}
+
+/// Extract Metal shader source from llama.cpp and compile it
+fn compileShaderLibrary(allocator: std.mem.Allocator, output_path: []const u8) !void {
+    // Path to ggml-metal.metal in vendor directory
+    const shader_source = "vendor/llama.cpp/ggml/src/ggml-metal/ggml-metal.metal";
+
+    // Verify shader source exists
+    std.fs.cwd().access(shader_source, .{}) catch |err| {
+        std.debug.print("  Error: Could not find {s}: {}\n", .{ shader_source, err });
+        return error.ShaderSourceNotFound;
+    };
+
+    // Create temporary directory for intermediate files
+    const tmp_dir = try std.fmt.allocPrint(allocator, "/tmp/zell-shader-{d}", .{std.time.milliTimestamp()});
+    defer allocator.free(tmp_dir);
+
+    std.fs.cwd().makePath(tmp_dir) catch |err| {
+        if (err != error.PathAlreadyExists) return err;
+    };
+    defer std.fs.cwd().deleteTree(tmp_dir) catch {};
+
+    const air_path = try std.fmt.allocPrint(allocator, "{s}/shader.air", .{tmp_dir});
+    defer allocator.free(air_path);
+
+    // Step 1: Compile .metal to .air (LLVM IR)
+    std.debug.print("  Compiling .metal to .air...\n", .{});
+    const compile_result = try std.process.Child.run(.{
+        .allocator = allocator,
+        .argv = &[_][]const u8{
+            "xcrun",
+            "-sdk",
+            "macosx",
+            "metal",
+            "-O3",
+            "-c",
+            shader_source,
+            "-o",
+            air_path,
+        },
+    });
+    defer allocator.free(compile_result.stdout);
+    defer allocator.free(compile_result.stderr);
+
+    if (compile_result.term.Exited != 0) {
+        std.debug.print("  Compilation stderr: {s}\n", .{compile_result.stderr});
+        return error.MetalCompilationFailed;
+    }
+
+    // Step 2: Link .air to .metallib
+    std.debug.print("  Linking .air to .metallib...\n", .{});
+    const link_result = try std.process.Child.run(.{
+        .allocator = allocator,
+        .argv = &[_][]const u8{
+            "xcrun",
+            "-sdk",
+            "macosx",
+            "metallib",
+            air_path,
+            "-o",
+            output_path,
+        },
+    });
+    defer allocator.free(link_result.stdout);
+    defer allocator.free(link_result.stderr);
+
+    if (link_result.term.Exited != 0) {
+        std.debug.print("  Linking stderr: {s}\n", .{link_result.stderr});
+        return error.MetalLinkingFailed;
+    }
+
+    std.debug.print("  ✅ Compiled shaders to {s}\n", .{output_path});
+}
+
+/// Load cached Metal shaders by setting environment variable
+/// Returns true if cached shaders are available
+pub fn useCachedShaders(allocator: std.mem.Allocator, model_path: []const u8) !bool {
+    const shader_path = try model_hash.getShaderPath(allocator, model_path);
+    defer allocator.free(shader_path);
+
+    // Check if cached shaders exist
+    std.fs.cwd().access(shader_path, .{}) catch {
+        return false;
+    };
+
+    // Set environment variable for llama.cpp to use
+    // Need null-terminated strings for C
+    const key_z = try allocator.dupeZ(u8, "ZELL_METAL_CACHE");
+    defer allocator.free(key_z);
+    const val_z = try allocator.dupeZ(u8, shader_path);
+    defer allocator.free(val_z);
+
+    _ = c.setenv(key_z.ptr, val_z.ptr, 1);
+
+    std.debug.print("Using pre-compiled Metal shaders from cache\n", .{});
+    return true;
+}
+
+/// Clear shader cache for a specific model
+pub fn clearShaderCache(allocator: std.mem.Allocator, model_path: []const u8) !void {
+    const shader_path = try model_hash.getShaderPath(allocator, model_path);
+    defer allocator.free(shader_path);
+
+    std.fs.cwd().deleteFile(shader_path) catch |err| {
+        if (err != error.FileNotFound) return err;
+    };
+}

